<?php
namespace App\Models\Customers;
use App\Models\Branch; use App\Models\Company; use App\Models\User; use Illuminate\Database\Eloquent\Attributes\Fillable; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Relations\BelongsTo; use Illuminate\Database\Eloquent\Relations\BelongsToMany; use Illuminate\Database\Eloquent\Relations\HasMany; use Illuminate\Database\Eloquent\Relations\HasOne; use Illuminate\Database\Eloquent\SoftDeletes;
#[Fillable(['company_id','branch_id','customer_number','first_name','last_name','display_name','email','phone','alternate_phone','whatsapp','gender','date_of_birth','anniversary_date','customer_type','status','source','tax_number','gstin','billing_address','shipping_address','city','state','country','postal_code','preferred_contact_method','notes','tags','created_by','last_purchase_at','last_return_at','total_purchase_amount','total_return_amount','total_orders_count','total_returns_count','loyalty_points_balance','wallet_balance','credit_limit','outstanding_balance','is_active'])]
class Customer extends Model { use SoftDeletes; protected $attributes = ['customer_type'=>'retail','status'=>'active','total_purchase_amount'=>0,'total_return_amount'=>0,'total_orders_count'=>0,'total_returns_count'=>0,'loyalty_points_balance'=>0,'wallet_balance'=>0,'outstanding_balance'=>0,'is_active'=>true]; protected function casts(): array { return ['date_of_birth'=>'date','anniversary_date'=>'date','last_purchase_at'=>'datetime','last_return_at'=>'datetime','tags'=>'array','is_active'=>'boolean']; } public function company(): BelongsTo{return $this->belongsTo(Company::class);} public function branch(): BelongsTo{return $this->belongsTo(Branch::class);} public function creator(): BelongsTo{return $this->belongsTo(User::class,'created_by');} public function addresses(): HasMany{return $this->hasMany(CustomerAddress::class);} public function contacts(): HasMany{return $this->hasMany(CustomerContact::class);} public function groups(): HasMany{return $this->hasMany(CustomerGroupMember::class);} public function customerGroups(): BelongsToMany{return $this->belongsToMany(CustomerGroup::class,'customer_group_members')->withPivot(['assigned_at','assigned_by','notes'])->withTimestamps();} public function activities(): HasMany{return $this->hasMany(CustomerActivityLog::class)->latest('occurred_at');} public function loyaltyAccount(): HasOne{return $this->hasOne(CustomerLoyaltyAccount::class);} public function walletTransactions(): HasMany{return $this->hasMany(CustomerWalletTransaction::class)->latest();} public function returnSummary(): HasOne{return $this->hasOne(CustomerReturnSummary::class);} public function insight(): HasOne{return $this->hasOne(CustomerInsightSnapshot::class);} }
